using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummaryService
{
    // Common English stop-words excluded from scoring.
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "its",
        "this", "that", "from", "as", "be", "been", "being", "have", "has",
        "had", "do", "does", "did", "will", "would", "could", "should",
        "may", "might", "shall", "can", "not", "no", "so", "if", "then",
        "than", "too", "very", "just", "about", "above", "after", "again",
        "all", "also", "am", "because", "before", "between", "both",
        "during", "each", "few", "further", "get", "got", "he", "she",
        "her", "here", "him", "his", "how", "i", "into", "me", "more",
        "most", "my", "nor", "now", "only", "other", "our", "out", "over",
        "own", "same", "some", "such", "there", "these", "they", "those",
        "through", "under", "until", "up", "we", "what", "when", "where",
        "which", "while", "who", "whom", "why", "you", "your"
    };

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency
    /// and returning the top-ranked ones in their original order.
    /// </summary>
    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((sentence, index) => (Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => sentences[s.Index]);

        return string.Join(" ", scored);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word))
                    frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
            }
        }
        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = Tokenize(sentence);
        if (words.Count == 0) return 0;

        double score = words
            .Where(w => !StopWords.Contains(w))
            .Sum(w => wordFrequencies.GetValueOrDefault(w));

        // Normalize by word count to avoid biasing toward long sentences.
        return score / words.Count;
    }

    private static List<string> Tokenize(string text)
    {
        return WordRegex()
            .Matches(text)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummaryService _summaryService;

    public SummarizeController(DocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

